-- Identity / tenant schema + RLS (BE-IDN-001).
-- Apply after 000004_inbox_and_worker_publisher.sql
-- Design: docs/data/identity-migration-design.md
-- Generated by tools/generate-identity-migration.mjs — re-run after permission_matrix.csv changes.

GRANT USAGE ON SCHEMA app TO app_runtime, app_worker;

-- ---------------------------------------------------------------------------
-- Tables
-- ---------------------------------------------------------------------------

CREATE TABLE IF NOT EXISTS app.tenants (
  id UUID PRIMARY KEY,
  code CITEXT NOT NULL,
  name TEXT NOT NULL CHECK (char_length(btrim(name)) > 0),
  status TEXT NOT NULL CHECK (status IN ('provisioning', 'active', 'suspended', 'closed')),
  timezone TEXT NOT NULL DEFAULT 'Asia/Ho_Chi_Minh',
  currency CHAR(3) NOT NULL DEFAULT 'VND',
  locale TEXT NOT NULL DEFAULT 'vi-VN',
  plan_id TEXT NULL,
  permission_version BIGINT NOT NULL DEFAULT 1 CHECK (permission_version >= 1),
  data_region TEXT NULL,
  version BIGINT NOT NULL DEFAULT 1 CHECK (version >= 1),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  created_by UUID NULL,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_by UUID NULL,
  suspended_at TIMESTAMPTZ NULL,
  closed_at TIMESTAMPTZ NULL,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  CONSTRAINT tenants_code_unique UNIQUE (code)
);

CREATE TABLE IF NOT EXISTS app.users (
  id UUID PRIMARY KEY,
  primary_email CITEXT NOT NULL,
  email_verified_at TIMESTAMPTZ NULL,
  status TEXT NOT NULL CHECK (status IN ('pending', 'active', 'locked', 'disabled', 'deleted')),
  locale TEXT NOT NULL DEFAULT 'vi-VN',
  last_login_at TIMESTAMPTZ NULL,
  anonymized_at TIMESTAMPTZ NULL,
  version BIGINT NOT NULL DEFAULT 1 CHECK (version >= 1),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb
);

CREATE UNIQUE INDEX IF NOT EXISTS uq_users_primary_email_active
  ON app.users (primary_email)
  WHERE anonymized_at IS NULL;

CREATE TABLE IF NOT EXISTS app.user_credentials (
  user_id UUID NOT NULL REFERENCES app.users (id),
  credential_type TEXT NOT NULL CHECK (credential_type IN ('password', 'oidc')),
  password_hash TEXT NULL,
  password_updated_at TIMESTAMPTZ NULL,
  failed_count INT NOT NULL DEFAULT 0 CHECK (failed_count >= 0),
  locked_until TIMESTAMPTZ NULL,
  provider TEXT NULL,
  provider_subject TEXT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (user_id, credential_type),
  CONSTRAINT user_credentials_password_hash_chk CHECK (
    credential_type <> 'password' OR password_hash IS NOT NULL
  ),
  CONSTRAINT user_credentials_oidc_chk CHECK (
    credential_type <> 'oidc'
    OR (provider IS NOT NULL AND provider_subject IS NOT NULL)
  )
);

CREATE TABLE IF NOT EXISTS app.tenant_memberships (
  id UUID PRIMARY KEY,
  tenant_id UUID NOT NULL REFERENCES app.tenants (id),
  user_id UUID NOT NULL REFERENCES app.users (id),
  status TEXT NOT NULL CHECK (status IN ('invited', 'active', 'suspended', 'revoked')),
  display_name TEXT NULL,
  title TEXT NULL,
  default_warehouse_id UUID NULL,
  invited_by UUID NULL REFERENCES app.users (id),
  activated_at TIMESTAMPTZ NULL,
  revoked_at TIMESTAMPTZ NULL,
  version BIGINT NOT NULL DEFAULT 1 CHECK (version >= 1),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  created_by UUID NULL,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_by UUID NULL,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  CONSTRAINT tenant_memberships_tenant_user_unique UNIQUE (tenant_id, user_id)
);

CREATE UNIQUE INDEX IF NOT EXISTS uq_tenant_memberships_id_tenant
  ON app.tenant_memberships (id, tenant_id);

CREATE TABLE IF NOT EXISTS app.roles (
  id UUID PRIMARY KEY,
  tenant_id UUID NULL REFERENCES app.tenants (id),
  name TEXT NOT NULL CHECK (char_length(btrim(name)) > 0),
  description TEXT NULL,
  is_system BOOLEAN NOT NULL DEFAULT false,
  version BIGINT NOT NULL DEFAULT 1 CHECK (version >= 1),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  created_by UUID NULL,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_by UUID NULL,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  CONSTRAINT roles_system_tenant_null_chk CHECK (
    (is_system = true AND tenant_id IS NULL)
    OR (is_system = false AND tenant_id IS NOT NULL)
  )
);

CREATE UNIQUE INDEX IF NOT EXISTS uq_roles_system_name
  ON app.roles (name)
  WHERE tenant_id IS NULL;

CREATE UNIQUE INDEX IF NOT EXISTS uq_roles_tenant_name
  ON app.roles (tenant_id, name)
  WHERE tenant_id IS NOT NULL;

CREATE TABLE IF NOT EXISTS app.permissions (
  key TEXT PRIMARY KEY CHECK (key ~ '^[a-z][a-z0-9_]*(\.[a-z][a-z0-9_]*)+$'),
  data_classification TEXT NOT NULL,
  description TEXT NOT NULL DEFAULT '',
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS app.role_permissions (
  role_id UUID NOT NULL REFERENCES app.roles (id) ON DELETE CASCADE,
  permission_key TEXT NOT NULL REFERENCES app.permissions (key),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (role_id, permission_key)
);

CREATE TABLE IF NOT EXISTS app.membership_roles (
  id UUID PRIMARY KEY,
  tenant_id UUID NOT NULL,
  membership_id UUID NOT NULL,
  role_id UUID NOT NULL REFERENCES app.roles (id),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  created_by UUID NULL,
  CONSTRAINT membership_roles_membership_fk
    FOREIGN KEY (membership_id, tenant_id)
    REFERENCES app.tenant_memberships (id, tenant_id),
  CONSTRAINT membership_roles_unique UNIQUE (tenant_id, membership_id, role_id)
);

CREATE TABLE IF NOT EXISTS app.devices (
  id UUID PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES app.users (id),
  platform TEXT NOT NULL CHECK (platform IN ('web', 'windows', 'ios', 'android', 'other')),
  label TEXT NULL,
  app_version TEXT NULL,
  push_capable BOOLEAN NOT NULL DEFAULT false,
  trusted BOOLEAN NOT NULL DEFAULT false,
  trust_status TEXT NOT NULL DEFAULT 'pending'
    CHECK (trust_status IN ('trusted', 'pending', 'revoked')),
  last_seen_at TIMESTAMPTZ NULL,
  revoked_at TIMESTAMPTZ NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb
);

CREATE INDEX IF NOT EXISTS idx_devices_user_revoked
  ON app.devices (user_id, revoked_at);

CREATE TABLE IF NOT EXISTS app.user_sessions (
  id UUID PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES app.users (id),
  tenant_id UUID NULL REFERENCES app.tenants (id),
  membership_id UUID NULL,
  device_id UUID NOT NULL REFERENCES app.devices (id),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  last_seen_at TIMESTAMPTZ NULL,
  absolute_expiry TIMESTAMPTZ NOT NULL,
  revoked_at TIMESTAMPTZ NULL,
  revoked BOOLEAN NOT NULL DEFAULT false,
  auth_methods TEXT[] NOT NULL DEFAULT '{}',
  ip_hash TEXT NULL,
  user_agent_hash TEXT NULL,
  version BIGINT NOT NULL DEFAULT 1 CHECK (version >= 1),
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb
);

CREATE INDEX IF NOT EXISTS idx_user_sessions_user_revoked_expiry
  ON app.user_sessions (user_id, revoked, absolute_expiry);

CREATE INDEX IF NOT EXISTS idx_user_sessions_tenant_user
  ON app.user_sessions (tenant_id, user_id)
  WHERE tenant_id IS NOT NULL;

CREATE TABLE IF NOT EXISTS app.refresh_tokens (
  id UUID PRIMARY KEY,
  session_id UUID NOT NULL REFERENCES app.user_sessions (id),
  user_id UUID NOT NULL REFERENCES app.users (id),
  tenant_id UUID NULL REFERENCES app.tenants (id),
  token_hash TEXT NOT NULL,
  family_id UUID NOT NULL,
  parent_id UUID NULL REFERENCES app.refresh_tokens (id),
  issued_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  used_at TIMESTAMPTZ NULL,
  revoked_at TIMESTAMPTZ NULL,
  expires_at TIMESTAMPTZ NOT NULL,
  reuse_detected_at TIMESTAMPTZ NULL,
  CONSTRAINT refresh_tokens_token_hash_unique UNIQUE (token_hash)
);

CREATE INDEX IF NOT EXISTS idx_refresh_tokens_family
  ON app.refresh_tokens (family_id);

CREATE INDEX IF NOT EXISTS idx_refresh_tokens_session
  ON app.refresh_tokens (session_id);

CREATE TABLE IF NOT EXISTS app.invitations (
  id UUID PRIMARY KEY,
  tenant_id UUID NOT NULL REFERENCES app.tenants (id),
  email CITEXT NOT NULL,
  token_hash TEXT NOT NULL,
  status TEXT NOT NULL CHECK (status IN ('pending', 'accepted', 'revoked', 'expired')),
  role_ids UUID[] NOT NULL DEFAULT '{}',
  invited_by UUID NULL REFERENCES app.users (id),
  expires_at TIMESTAMPTZ NOT NULL,
  accepted_at TIMESTAMPTZ NULL,
  revoked_at TIMESTAMPTZ NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  CONSTRAINT invitations_token_hash_unique UNIQUE (token_hash)
);

CREATE UNIQUE INDEX IF NOT EXISTS uq_invitations_tenant_email_pending
  ON app.invitations (tenant_id, email)
  WHERE status = 'pending';

CREATE TABLE IF NOT EXISTS app.mfa_factors (
  id UUID PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES app.users (id),
  factor_type TEXT NOT NULL CHECK (factor_type IN ('totp')),
  secret_encrypted BYTEA NOT NULL,
  label TEXT NULL,
  verified_at TIMESTAMPTZ NULL,
  disabled_at TIMESTAMPTZ NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_mfa_factors_user
  ON app.mfa_factors (user_id)
  WHERE disabled_at IS NULL;

CREATE TABLE IF NOT EXISTS app.recovery_codes (
  id UUID PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES app.users (id),
  code_hash TEXT NOT NULL,
  used_at TIMESTAMPTZ NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  CONSTRAINT recovery_codes_hash_unique UNIQUE (code_hash)
);

CREATE INDEX IF NOT EXISTS idx_recovery_codes_user
  ON app.recovery_codes (user_id)
  WHERE used_at IS NULL;

CREATE TABLE IF NOT EXISTS app.support_access_grants (
  id UUID PRIMARY KEY,
  tenant_id UUID NOT NULL REFERENCES app.tenants (id),
  grantee_user_id UUID NOT NULL REFERENCES app.users (id),
  reason TEXT NOT NULL CHECK (char_length(btrim(reason)) > 0),
  ticket_ref TEXT NULL,
  scope TEXT NOT NULL DEFAULT 'read',
  approved_by UUID NULL REFERENCES app.users (id),
  expires_at TIMESTAMPTZ NOT NULL,
  revoked_at TIMESTAMPTZ NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  created_by UUID NULL,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb
);

CREATE INDEX IF NOT EXISTS idx_support_access_grants_tenant_active
  ON app.support_access_grants (tenant_id, expires_at)
  WHERE revoked_at IS NULL;

-- ---------------------------------------------------------------------------
-- RLS
-- ---------------------------------------------------------------------------

-- TENANT_ROOT
ALTER TABLE app.tenants ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.tenants FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS tenants_tenant_root ON app.tenants;
CREATE POLICY tenants_tenant_root ON app.tenants
  FOR ALL TO app_runtime, app_worker
  USING (id = nullif(current_setting('app.tenant_id', true), '')::uuid)
  WITH CHECK (id = nullif(current_setting('app.tenant_id', true), '')::uuid);

-- GLOBAL catalogs / identity
ALTER TABLE app.users ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.users FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS users_self_read ON app.users;
CREATE POLICY users_self_read ON app.users
  FOR SELECT TO app_runtime, app_worker
  USING (id = nullif(current_setting('app.actor_id', true), '')::uuid);
DROP POLICY IF EXISTS users_self_write ON app.users;
CREATE POLICY users_self_write ON app.users
  FOR INSERT TO app_runtime, app_worker
  WITH CHECK (id = nullif(current_setting('app.actor_id', true), '')::uuid);
DROP POLICY IF EXISTS users_self_update ON app.users;
CREATE POLICY users_self_update ON app.users
  FOR UPDATE TO app_runtime, app_worker
  USING (id = nullif(current_setting('app.actor_id', true), '')::uuid)
  WITH CHECK (id = nullif(current_setting('app.actor_id', true), '')::uuid);
-- Cross-user provisioning (invite accept / OIDC subject bind) uses SECURITY DEFINER in later IDN tickets.

ALTER TABLE app.user_credentials ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.user_credentials FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS user_credentials_self ON app.user_credentials;
CREATE POLICY user_credentials_self ON app.user_credentials
  FOR ALL TO app_runtime, app_worker
  USING (user_id = nullif(current_setting('app.actor_id', true), '')::uuid)
  WITH CHECK (user_id = nullif(current_setting('app.actor_id', true), '')::uuid);

ALTER TABLE app.permissions ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.permissions FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS permissions_read_all ON app.permissions;
CREATE POLICY permissions_read_all ON app.permissions
  FOR SELECT TO app_runtime, app_worker
  USING (true);

ALTER TABLE app.devices ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.devices FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS devices_owner ON app.devices;
CREATE POLICY devices_owner ON app.devices
  FOR ALL TO app_runtime, app_worker
  USING (user_id = nullif(current_setting('app.actor_id', true), '')::uuid)
  WITH CHECK (user_id = nullif(current_setting('app.actor_id', true), '')::uuid);

ALTER TABLE app.mfa_factors ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.mfa_factors FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS mfa_factors_owner ON app.mfa_factors;
CREATE POLICY mfa_factors_owner ON app.mfa_factors
  FOR ALL TO app_runtime, app_worker
  USING (user_id = nullif(current_setting('app.actor_id', true), '')::uuid)
  WITH CHECK (user_id = nullif(current_setting('app.actor_id', true), '')::uuid);

ALTER TABLE app.recovery_codes ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.recovery_codes FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS recovery_codes_owner ON app.recovery_codes;
CREATE POLICY recovery_codes_owner ON app.recovery_codes
  FOR ALL TO app_runtime, app_worker
  USING (user_id = nullif(current_setting('app.actor_id', true), '')::uuid)
  WITH CHECK (user_id = nullif(current_setting('app.actor_id', true), '')::uuid);

-- TENANT_OWNED
ALTER TABLE app.tenant_memberships ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.tenant_memberships FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS tenant_memberships_isolation ON app.tenant_memberships;
CREATE POLICY tenant_memberships_isolation ON app.tenant_memberships
  FOR ALL TO app_runtime, app_worker
  USING (tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid)
  WITH CHECK (tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid);

ALTER TABLE app.membership_roles ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.membership_roles FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS membership_roles_isolation ON app.membership_roles;
CREATE POLICY membership_roles_isolation ON app.membership_roles
  FOR ALL TO app_runtime, app_worker
  USING (tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid)
  WITH CHECK (tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid);

ALTER TABLE app.invitations ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.invitations FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS invitations_isolation ON app.invitations;
CREATE POLICY invitations_isolation ON app.invitations
  FOR ALL TO app_runtime, app_worker
  USING (tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid)
  WITH CHECK (tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid);

ALTER TABLE app.support_access_grants ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.support_access_grants FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS support_access_grants_isolation ON app.support_access_grants;
CREATE POLICY support_access_grants_isolation ON app.support_access_grants
  FOR ALL TO app_runtime, app_worker
  USING (tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid)
  WITH CHECK (tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid);

-- HYBRID roles
ALTER TABLE app.roles ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.roles FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS roles_hybrid ON app.roles;
CREATE POLICY roles_hybrid ON app.roles
  FOR SELECT TO app_runtime, app_worker
  USING (
    tenant_id IS NULL
    OR tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid
  );
DROP POLICY IF EXISTS roles_hybrid_write ON app.roles;
CREATE POLICY roles_hybrid_write ON app.roles
  FOR INSERT TO app_runtime, app_worker
  WITH CHECK (tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid);
DROP POLICY IF EXISTS roles_hybrid_update ON app.roles;
CREATE POLICY roles_hybrid_update ON app.roles
  FOR UPDATE TO app_runtime, app_worker
  USING (tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid)
  WITH CHECK (tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid);
DROP POLICY IF EXISTS roles_hybrid_delete ON app.roles;
CREATE POLICY roles_hybrid_delete ON app.roles
  FOR DELETE TO app_runtime, app_worker
  USING (tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid);

-- HYBRID role_permissions via parent role
ALTER TABLE app.role_permissions ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.role_permissions FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS role_permissions_hybrid_select ON app.role_permissions;
CREATE POLICY role_permissions_hybrid_select ON app.role_permissions
  FOR SELECT TO app_runtime, app_worker
  USING (
    EXISTS (
      SELECT 1 FROM app.roles r
      WHERE r.id = role_id
        AND (
          r.tenant_id IS NULL
          OR r.tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid
        )
    )
  );
DROP POLICY IF EXISTS role_permissions_hybrid_write ON app.role_permissions;
CREATE POLICY role_permissions_hybrid_write ON app.role_permissions
  FOR ALL TO app_runtime, app_worker
  USING (
    EXISTS (
      SELECT 1 FROM app.roles r
      WHERE r.id = role_id
        AND r.tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM app.roles r
      WHERE r.id = role_id
        AND r.tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid
    )
  );

-- Nullable-tenant sessions (definitive — identity-migration-design.md)
ALTER TABLE app.user_sessions ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.user_sessions FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS user_sessions_actor_tenant_isolation ON app.user_sessions;
CREATE POLICY user_sessions_actor_tenant_isolation ON app.user_sessions
  FOR ALL TO app_runtime, app_worker
  USING (
    user_id = nullif(current_setting('app.actor_id', true), '')::uuid
    AND (
      tenant_id IS NULL
      OR tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid
    )
  )
  WITH CHECK (
    user_id = nullif(current_setting('app.actor_id', true), '')::uuid
    AND (
      tenant_id IS NULL
      OR tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid
    )
  );

-- refresh_tokens: denormalized user_id + tenant_id (same predicate)
ALTER TABLE app.refresh_tokens ENABLE ROW LEVEL SECURITY;
ALTER TABLE app.refresh_tokens FORCE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS refresh_tokens_actor_tenant_isolation ON app.refresh_tokens;
CREATE POLICY refresh_tokens_actor_tenant_isolation ON app.refresh_tokens
  FOR ALL TO app_runtime, app_worker
  USING (
    user_id = nullif(current_setting('app.actor_id', true), '')::uuid
    AND (
      tenant_id IS NULL
      OR tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid
    )
  )
  WITH CHECK (
    user_id = nullif(current_setting('app.actor_id', true), '')::uuid
    AND (
      tenant_id IS NULL
      OR tenant_id = nullif(current_setting('app.tenant_id', true), '')::uuid
    )
  );

